// First Missing Positive - O(n) time, O(1) space
public int firstMissingPositive(int[] nums) {
    int n = nums.length;

    // Step 1: Place each number at its correct index
    // Number k should be at index k-1
    for (int i = 0; i < n; i++) {
        // Keep swapping until current number is:
        // - Out of range [1, n], OR
        // - Already at correct position
        while (nums[i] > 0 && nums[i] <= n 
               && nums[nums[i] - 1] != nums[i]) {
            // Swap nums[i] with nums[nums[i] - 1]
            int correctIdx = nums[i] - 1;
            int temp = nums[correctIdx];
            nums[correctIdx] = nums[i];
            nums[i] = temp;
        }
    }

    // Step 2: Find first position where number != index + 1
    for (int i = 0; i < n; i++) {
        if (nums[i] != i + 1) {
            return i + 1;
        }
    }

    // All positions filled correctly
    return n + 1;
}

// Find All Duplicates in Array
// Numbers in range [1, n], some appear twice
public List<Integer> findDuplicates(int[] nums) {
    List<Integer> result = new ArrayList<>();

    // Mark visited by negating at index
    for (int num : nums) {
        int idx = Math.abs(num) - 1;
        if (nums[idx] < 0) {
            result.add(Math.abs(num));  // Already visited = duplicate
        } else {
            nums[idx] = -nums[idx];  // Mark as visited
        }
    }

    return result;
}

