// Remove Duplicates from Sorted Array - In Place
public int removeDuplicates(int[] nums) {
    if (nums.length == 0) return 0;

    int writePtr = 1;  // Position to write next unique

    for (int readPtr = 1; readPtr < nums.length; readPtr++) {
        // If current is different from previous unique
        if (nums[readPtr] != nums[writePtr - 1]) {
            nums[writePtr] = nums[readPtr];
            writePtr++;
        }
    }

    return writePtr;  // Length of unique portion
}

// Rotate Array by k positions
public void rotate(int[] nums, int k) {
    int n = nums.length;
    k = k % n;  // Handle k > n

    // Three reverses
    reverse(nums, 0, n - 1);     // Reverse all
    reverse(nums, 0, k - 1);     // Reverse first k
    reverse(nums, k, n - 1);     // Reverse remaining
}

private void reverse(int[] nums, int start, int end) {
    while (start < end) {
        int temp = nums[start];
        nums[start] = nums[end];
        nums[end] = temp;
        start++;
        end--;
    }
}

// Move Zeroes to End
public void moveZeroes(int[] nums) {
    int writePtr = 0;  // Position to write non-zero

    // Move all non-zeroes to front
    for (int num : nums) {
        if (num != 0) {
            nums[writePtr++] = num;
        }
    }

    // Fill rest with zeroes
    while (writePtr < nums.length) {
        nums[writePtr++] = 0;
    }
}

