public boolean exist(char[][] board, String word) {
    int m = board.length, n = board[0].length;

    // Try starting from each cell
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (backtrack(board, word, i, j, 0)) {
                return true;
            }
        }
    }
    return false;
}

boolean backtrack(char[][] board, String word, int i, int j, int k) {
    // Base case: found all characters
    if (k == word.length()) return true;

    // Boundary check
    if (i < 0 || i >= board.length || 
        j < 0 || j >= board[0].length) return false;

    // Character mismatch
    if (board[i][j] != word.charAt(k)) return false;

    // Mark as visited
    char temp = board[i][j];
    board[i][j] = '#';

    // Explore 4 directions
    boolean found = backtrack(board, word, i + 1, j, k + 1) ||
                    backtrack(board, word, i - 1, j, k + 1) ||
                    backtrack(board, word, i, j + 1, k + 1) ||
                    backtrack(board, word, i, j - 1, k + 1);

    // Backtrack: restore cell
    board[i][j] = temp;

    return found;
}

