public List<List<String>> solveNQueens(int n) {
    List<List<String>> result = new ArrayList<>();
    // Track which columns and diagonals are under attack
    Set<Integer> cols = new HashSet<>();
    Set<Integer> diag1 = new HashSet<>();  // row - col
    Set<Integer> diag2 = new HashSet<>();  // row + col

    backtrack(n, 0, new ArrayList<>(), cols, diag1, diag2, result);
    return result;
}

void backtrack(int n, int row, List<String> board,
               Set<Integer> cols, Set<Integer> diag1, Set<Integer> diag2,
               List<List<String>> result) {
    if (row == n) {
        result.add(new ArrayList<>(board));
        return;
    }

    for (int col = 0; col < n; col++) {
        // Check if position is safe
        if (cols.contains(col) || 
            diag1.contains(row - col) || 
            diag2.contains(row + col)) {
            continue;
        }

        // Place queen
        char[] rowArr = new char[n];
        Arrays.fill(rowArr, '.');
        rowArr[col] = 'Q';
        board.add(new String(rowArr));
        cols.add(col);
        diag1.add(row - col);
        diag2.add(row + col);

        // Recurse
        backtrack(n, row + 1, board, cols, diag1, diag2, result);

        // Backtrack
        board.remove(board.size() - 1);
        cols.remove(col);
        diag1.remove(row - col);
        diag2.remove(row + col);
    }
}

