    int left = 0, right = arr.length - 1;

    while (left < right) {
        int mid = left + (right - left) / 2;

        if (arr[mid] < arr[mid + 1]) {
            left = mid + 1;  // Still climbing
        } else {
            right = mid;  // Past peak or at peak
        }
    }

    return left;
}

