/*
 * LIS PATTERN
 * STATE: dp[i] = length of LIS ending at index i
 * DECISION: For each j < i, can we extend LIS ending at j?
 */

// O(n^2) DP Solution - Easy to understand
public int lengthOfLIS(int[] nums) {
    int n = nums.length;
    int[] dp = new int[n];
    Arrays.fill(dp, 1);  // Each element is LIS of length 1
    int maxLen = 1;

    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (nums[j] < nums[i]) {  // Can extend?
                dp[i] = Math.max(dp[i], dp[j] + 1);
            }
        }
        maxLen = Math.max(maxLen, dp[i]);
    }
    return maxLen;
}

// O(n log n) Binary Search - Optimal
public int lengthOfLISOptimal(int[] nums) {
    List<Integer> tails = new ArrayList<>();
    // tails[i] = smallest tail of all LIS of length i+1

    for (int num : nums) {
        int pos = Collections.binarySearch(tails, num);
        if (pos < 0) pos = -(pos + 1);

        if (pos == tails.size()) {
            tails.add(num);  // Extend LIS
        } else {
            tails.set(pos, num);  // Replace with smaller
        }
    }
    return tails.size();
}

