                    const newChar = String.fromCharCode(c);
                    if (newChar === original) continue;
                    chars[j] = newChar;
                    const newWord = chars.join('');

                    if (newWord === endWord) return level + 1;
                    if (wordSet.has(newWord) && !visited.has(newWord)) {
                        visited.add(newWord);
                        queue.push(newWord);
                    }
                }
                chars[j] = original;
            }
        }
        level++;
    }
    return 0;
}

