public int longestConsecutive(int[] nums) {
    Set<Integer> numSet = new HashSet<>();
    for (int num : nums) {
        numSet.add(num);
    }

    int longest = 0;

    for (int num : numSet) {
        // Only start from beginning of a sequence
        if (!numSet.contains(num - 1)) {
            int currentNum = num;
            int length = 1;

            // Extend the sequence
            while (numSet.contains(currentNum + 1)) {
                currentNum++;
                length++;
            }

            longest = Math.max(longest, length);
        }
    }

    return longest;
}

