public int findMaxLength(int[] nums) {
    Map<Integer, Integer> firstSeen = new HashMap<>();
    firstSeen.put(0, -1);  // Sum 0 seen at index -1 (before array)

    int sum = 0, maxLen = 0;

    for (int i = 0; i < nums.length; i++) {
        // Transform: 0 → -1, 1 → +1
        sum += (nums[i] == 0) ? -1 : 1;

        if (firstSeen.containsKey(sum)) {
            // Same sum seen before → subarray between has sum 0
            maxLen = Math.max(maxLen, i - firstSeen.get(sum));
        } else {
            firstSeen.put(sum, i);  // Record first occurrence
        }
    }

    return maxLen;
}

