function findAnagrams(s, p) {
    const result = [];
    const pFreq = new Map();
    const sFreq = new Map();

    // Build pattern frequency map
    for (const c of p) {
        pFreq.set(c, (pFreq.get(c) || 0) + 1);
    }

    let matches = 0;
    const required = pFreq.size;

    for (let i = 0; i < s.length; i++) {
        const c = s[i];
        sFreq.set(c, (sFreq.get(c) || 0) + 1);

        if (sFreq.get(c) === pFreq.get(c)) matches++;
        else if (sFreq.get(c) === pFreq.get(c) + 1) matches--;

        if (i >= p.length) {
            const left = s[i - p.length];
            if (sFreq.get(left) === pFreq.get(left)) matches--;
            else if (sFreq.get(left) === pFreq.get(left) + 1) matches++;
            sFreq.set(left, sFreq.get(left) - 1);
        }

        if (matches === required) result.push(i - p.length + 1);
    }
    return result;
}

