            countStack.push(num);
            strStack.push(curr);
            num = 0;
            curr = new StringBuilder();
        } else if (c == ']') {
            int count = countStack.pop();
            StringBuilder prev = strStack.pop();
            String repeated = curr.toString().repeat(count);
