    }

    addWord(word) {
        let node = this.root;
        for (const c of word) {
            if (!node[c]) node[c] = {};
            node = node[c];
        }
        node.isEnd = true;
    }

    search(word) {
        return this._searchHelper(word, 0, this.root);
    }

    _searchHelper(word, index, node) {
        if (!node) return false;
        if (index === word.length) return node.isEnd === true;

        const char = word[index];

        if (char === '.') {
            // Wildcard: try ALL children
            for (const key of Object.keys(node)) {
                if (key !== 'isEnd' && 
                    this._searchHelper(word, index + 1, node[key])) {
                    return true;
                }
            }
            return false;
        } else {
            // Normal character
            return this._searchHelper(word, index + 1, node[char]);
        }
    }
}

