function findRedundantConnection(edges) {
    const n = edges.length;
    const uf = new UnionFind(n + 1); // 1-indexed nodes

    for (const [u, v] of edges) {
        // If already connected, this edge creates a cycle
        if (uf.find(u) === uf.find(v)) {
            return [u, v];
        }
        uf.union(u, v);
    }

    return [];
}

