public int[] findRedundantConnection(int[][] edges) {
    int n = edges.length;
    UnionFind uf = new UnionFind(n + 1);

    for (int[] edge : edges) {
        int u = edge[0], v = edge[1];
        if (uf.find(u) == uf.find(v)) {
            return edge; // Cycle detected
        }
        uf.union(u, v);
    }

    return new int[0];
}

